### **Step-by-Step Submission Process**

#### 1. **Define the User Data Model**

```javascript
// models/UserApplication.js
const mongoose = require('mongoose');

const userApplicationSchema = new mongoose.Schema({
  name: String,
  email: String,
  resume: String,
  position: String,
  submittedAt: { type: Date, default: Date.now }
});

module.exports = mongoose.model('UserApplication', userApplicationSchema);
```

#### 2. **Connect to MongoDB**

```javascript
// db.js
const mongoose = require('mongoose');
const mongoURI = 'mongodb://prod-db.company.com:27017/userdata';

mongoose.connect(mongoURI, { useNewUrlParser: true, useUnifiedTopology: true });

mongoose.connection.on('connected', () => {
  console.log('Connected to MongoDB');
});
```

#### 3. **Express Endpoint to Submit Job Application**

```javascript
// app.js
const express = require('express');
const UserApplication = require('./models/UserApplication');
require('./db');

const app = express();
app.use(express.json());

app.post('/submit-application', async (req, res) => {
  try {
    const { name, email, resume, position } = req.body;

    // Basic validation
    if (!name || !email || !resume || !position) {
      return res.status(400).json({ message: 'All fields are required.' });
    }

    // Store in MongoDB
    const application = new UserApplication({ name, email, resume, position });
    await application.save();

    // Return confirmation
    return res.status(201).json({
      message: 'Application submitted successfully!',
      applicationId: application._id,
      confirmation: {
        name,
        position,
        submittedAt: application.submittedAt
      }
    });
  } catch (err) {
    return res.status(500).json({ message: 'Submission failed.', error: err.message });
  }
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});
```

